.mrg-blockquote {
  background: var(--mrg-semantic-color-background-surface);
  border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-default);
  border-radius: var(--mrg-semantic-radius-panel);
  color: var(--mrg-semantic-color-foreground-primary);
  font-family: var(--mrg-semantic-font-family-prose);
  margin: 0;
  max-inline-size: var(--mrg-semantic-container-prose);
  overflow-wrap: anywhere;
  padding: var(--mrg-semantic-density-panel-padding);
}
.mrg-blockquote [data-slot="blockquote-quote"] {
  font-size: var(--mrg-semantic-font-size-body-large);
  line-height: var(--mrg-semantic-font-line-height-body);
  margin: 0;
  text-wrap: pretty;
}
.mrg-blockquote [data-slot="blockquote-caption"] {
  align-items: baseline;
  display: flex;
  flex-wrap: wrap;
  gap: var(--mrg-semantic-space-inline-sm);
  margin-block-start: var(--mrg-semantic-space-stack-md);
}
.mrg-blockquote [data-slot="blockquote-attribution"] {
  font-weight: var(--mrg-semantic-font-weight-label);
}
.mrg-blockquote [data-slot="blockquote-source"] {
  color: var(--mrg-semantic-color-foreground-muted);
}
.mrg-blockquote [data-slot="blockquote-source"]::before {
  content: "— ";
}
.mrg-blockquote a {
  color: var(--mrg-semantic-color-brand-action);
  text-underline-offset: 0.18em;
}
@media (forced-colors: active) {
  .mrg-blockquote {
    background: Canvas;
    border-color: CanvasText;
    color: CanvasText;
  }
  .mrg-blockquote [data-slot="blockquote-source"] {
    color: CanvasText;
  }
  .mrg-blockquote a {
    color: LinkText;
  }
}

import { forwardRef, type HTMLAttributes, type ReactNode } from "react";

import "./blockquote.css";

export interface BlockquoteProps extends HTMLAttributes<HTMLElement> {
  readonly attribution?: ReactNode;
  readonly children: ReactNode;
  readonly citeUrl?: string;
  readonly sourceTitle?: ReactNode;
}

export const Blockquote = forwardRef<HTMLElement, BlockquoteProps>(function Blockquote(
  { attribution, children, citeUrl, className, sourceTitle, ...nativeProps },
  forwardedRef,
) {
  const hasCaption = attribution !== undefined || sourceTitle !== undefined;
  return (
    <figure
      {...nativeProps}
      ref={forwardedRef}
      className={
        className === undefined || className.trim().length === 0
          ? "mrg-blockquote"
          : `mrg-blockquote ${className}`
      }
      data-slot="blockquote"
    >
      <blockquote cite={citeUrl} data-slot="blockquote-quote">
        {children}
      </blockquote>
      {hasCaption ? (
        <figcaption data-slot="blockquote-caption">
          {attribution !== undefined ? (
            <span data-slot="blockquote-attribution">{attribution}</span>
          ) : null}
          {sourceTitle !== undefined ? (
            <cite data-slot="blockquote-source">
              {citeUrl === undefined ? sourceTitle : <a href={citeUrl}>{sourceTitle}</a>}
            </cite>
          ) : null}
        </figcaption>
      ) : null}
    </figure>
  );
});

Blockquote.displayName = "Blockquote";
